+impl InterceptStats {
+    /// Render ARS interception counters as Prometheus exposition text.
+    pub fn render_prometheus(&self, prefix: &str) -> String {
+        let sanitized_prefix = sanitize_metric_prefix(prefix);
+        let mut out = String::new();
+        let _ = writeln!(
